import { Component } from '@odoo/owl'
import { useForm, validators, Fetch, router } from 'metaowl'

export default class LoginPage extends Component {
  static template = 'LoginPage'

  setup() {
    this.form = useForm({
      email:    { default: '', validation: [validators.required(), validators.email()] },
      password: { default: '', validation: [validators.required(), validators.minLength(8)] },
    })

    this.submitHandler = this.form.handleSubmit(async (values) => {
      await Fetch.url('/api/login', 'POST', values)
      router.push('/dashboard')
    })
  }
}

this.form = useForm({
  email: { default: '', validation: [validators.required(), validators.email()] },
  role:  { default: 'user' },  // No validation needed
})

// Access values via form.fields
console.log(this.form.fields.email)  // ''
console.log(this.form.fields.role)   // 'user'
